-- DMT_V_AP_INVOICES_DETAIL
CREATE OR REPLACE EDITIONABLE VIEW "DMT_V_AP_INVOICES_DETAIL" ("RUN_STATUS", "ERROR_TEXT", "RECONCILIATION_STATUS", "INVOICE_NUM", "VENDOR_NAME", "INVOICE_ID", "OPERATING_UNIT", "SOURCE", "INVOICE_AMOUNT", "INVOICE_DATE", "VENDOR_NUM", "VENDOR_SITE_CODE", "INVOICE_CURRENCY_CODE", "PAYMENT_CURRENCY_CODE", "DESCRIPTION", "GROUP_ID", "INVOICE_TYPE_LOOKUP_CODE", "LEGAL_ENTITY_NAME", "CUST_REGISTRATION_NUMBER", "CUST_REGISTRATION_CODE", "FIRST_PARTY_REGISTRATION_NUM", "THIRD_PARTY_REGISTRATION_NUM", "TERMS_NAME", "TERMS_DATE", "GOODS_RECEIVED_DATE", "INVOICE_RECEIVED_DATE", "GL_DATE", "PAYMENT_METHOD_CODE", "PAY_GROUP_LOOKUP_CODE", "EXCLUSIVE_PAYMENT_FLAG", "AMOUNT_APPLICABLE_TO_DISCOUNT", "PREPAY_NUM", "PREPAY_LINE_NUM", "PREPAY_APPLY_AMOUNT", "PREPAY_GL_DATE", "INVOICE_INCLUDES_PREPAY_FLAG", "EXCHANGE_RATE_TYPE", "EXCHANGE_DATE", "EXCHANGE_RATE", "ACCTS_PAY_CODE_CONCATENATED", "DOC_CATEGORY_CODE", "VOUCHER_NUM", "REQUESTER_FIRST_NAME", "REQUESTER_LAST_NAME", "REQUESTER_EMPLOYEE_NUM", "DELIVERY_CHANNEL_CODE", "BANK_CHARGE_BEARER", "REMIT_TO_SUPPLIER_NAME", "REMIT_TO_SUPPLIER_NUM", "REMIT_TO_ADDRESS_NAME", "PAYMENT_PRIORITY", "SETTLEMENT_PRIORITY", "UNIQUE_REMITTANCE_IDENTIFIER", "URI_CHECK_DIGIT", "PAYMENT_REASON_CODE", "PAYMENT_REASON_COMMENTS", "REMITTANCE_MESSAGE1", "REMITTANCE_MESSAGE2", "REMITTANCE_MESSAGE3", "AWT_GROUP_NAME", "SHIP_TO_LOCATION", "TAXATION_COUNTRY", "DOCUMENT_SUB_TYPE", "TAX_INVOICE_INTERNAL_SEQ", "SUPPLIER_TAX_INVOICE_NUMBER", "TAX_INVOICE_RECORDING_DATE", "SUPPLIER_TAX_INVOICE_DATE", "SUPPLIER_TAX_EXCHANGE_RATE", "PORT_OF_ENTRY_CODE", "CORRECTION_YEAR", "CORRECTION_PERIOD", "IMPORT_DOCUMENT_NUMBER", "IMPORT_DOCUMENT_DATE", "CONTROL_AMOUNT", "CALC_TAX_DURING_IMPORT_FLAG", "ADD_TAX_TO_INV_AMT_FLAG", "ATTRIBUTE_CATEGORY", "ATTRIBUTE1", "ATTRIBUTE2", "ATTRIBUTE3", "ATTRIBUTE4", "ATTRIBUTE5", "ATTRIBUTE6", "ATTRIBUTE7", "ATTRIBUTE8", "ATTRIBUTE9", "ATTRIBUTE10", "ATTRIBUTE11", "ATTRIBUTE12", "ATTRIBUTE13", "ATTRIBUTE14", "ATTRIBUTE15", "ATTRIBUTE_NUMBER1", "ATTRIBUTE_NUMBER2", "ATTRIBUTE_NUMBER3", "ATTRIBUTE_NUMBER4", "ATTRIBUTE_NUMBER5", "ATTRIBUTE_DATE1", "ATTRIBUTE_DATE2", "ATTRIBUTE_DATE3", "ATTRIBUTE_DATE4", "ATTRIBUTE_DATE5", "GLOBAL_ATTRIBUTE_CATEGORY", "GLOBAL_ATTRIBUTE1", "GLOBAL_ATTRIBUTE2", "GLOBAL_ATTRIBUTE3", "GLOBAL_ATTRIBUTE4", "GLOBAL_ATTRIBUTE5", "GLOBAL_ATTRIBUTE6", "GLOBAL_ATTRIBUTE7", "GLOBAL_ATTRIBUTE8", "GLOBAL_ATTRIBUTE9", "GLOBAL_ATTRIBUTE10", "GLOBAL_ATTRIBUTE11", "GLOBAL_ATTRIBUTE12", "GLOBAL_ATTRIBUTE13", "GLOBAL_ATTRIBUTE14", "GLOBAL_ATTRIBUTE15", "GLOBAL_ATTRIBUTE16", "GLOBAL_ATTRIBUTE17", "GLOBAL_ATTRIBUTE18", "GLOBAL_ATTRIBUTE19", "GLOBAL_ATTRIBUTE20", "GLOBAL_ATTRIBUTE_NUMBER1", "GLOBAL_ATTRIBUTE_NUMBER2", "GLOBAL_ATTRIBUTE_NUMBER3", "GLOBAL_ATTRIBUTE_NUMBER4", "GLOBAL_ATTRIBUTE_NUMBER5", "GLOBAL_ATTRIBUTE_DATE1", "GLOBAL_ATTRIBUTE_DATE2", "GLOBAL_ATTRIBUTE_DATE3", "GLOBAL_ATTRIBUTE_DATE4", "GLOBAL_ATTRIBUTE_DATE5", "IMAGE_DOCUMENT_URI", "EXTERNAL_BANK_ACCOUNT_NUMBER", "EXT_BANK_ACCOUNT_IBAN_NUMBER", "REQUESTER_EMAIL_ADDRESS", "INTERCOMPANY_CROSSCHARGE_FLAG", "SOURCE_ID", "STG_SEQUENCE_ID", "RUN_ID", "PREFIX", "SCENARIO_ID", "STAGE_DATE", "LAST_UPDATED_DATE")  AS 
  SELECT
    -- 1. Run status
    NVL(tfm.TFM_STATUS, stg.STG_STATUS)                             AS RUN_STATUS,
    -- 2. Error text
    tfm.ERROR_TEXT                                           AS ERROR_TEXT,
    CASE
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'LOADED' THEN 'CONFIRMED'
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NOT NULL THEN 'CONFIRMED'
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NULL THEN 'UNRECONCILED'
        ELSE 'IN_PROGRESS'
    END                                                      AS RECONCILIATION_STATUS,
    -- 3. Human identifiers
    stg.INVOICE_NUM                                         AS INVOICE_NUM,
    stg.VENDOR_NAME                                         AS VENDOR_NAME,
    -- 4. All remaining STG business columns
    stg.INVOICE_ID,
    stg.OPERATING_UNIT,
    stg.SOURCE,
    stg.INVOICE_AMOUNT,
    stg.INVOICE_DATE,
    stg.VENDOR_NUM,
    stg.VENDOR_SITE_CODE,
    stg.INVOICE_CURRENCY_CODE,
    stg.PAYMENT_CURRENCY_CODE,
    stg.DESCRIPTION,
    stg.GROUP_ID,
    stg.INVOICE_TYPE_LOOKUP_CODE,
    stg.LEGAL_ENTITY_NAME,
    stg.CUST_REGISTRATION_NUMBER,
    stg.CUST_REGISTRATION_CODE,
    stg.FIRST_PARTY_REGISTRATION_NUM,
    stg.THIRD_PARTY_REGISTRATION_NUM,
    stg.TERMS_NAME,
    stg.TERMS_DATE,
    stg.GOODS_RECEIVED_DATE,
    stg.INVOICE_RECEIVED_DATE,
    stg.GL_DATE,
    stg.PAYMENT_METHOD_CODE,
    stg.PAY_GROUP_LOOKUP_CODE,
    stg.EXCLUSIVE_PAYMENT_FLAG,
    stg.AMOUNT_APPLICABLE_TO_DISCOUNT,
    stg.PREPAY_NUM,
    stg.PREPAY_LINE_NUM,
    stg.PREPAY_APPLY_AMOUNT,
    stg.PREPAY_GL_DATE,
    stg.INVOICE_INCLUDES_PREPAY_FLAG,
    stg.EXCHANGE_RATE_TYPE,
    stg.EXCHANGE_DATE,
    stg.EXCHANGE_RATE,
    stg.ACCTS_PAY_CODE_CONCATENATED,
    stg.DOC_CATEGORY_CODE,
    stg.VOUCHER_NUM,
    stg.REQUESTER_FIRST_NAME,
    stg.REQUESTER_LAST_NAME,
    stg.REQUESTER_EMPLOYEE_NUM,
    stg.DELIVERY_CHANNEL_CODE,
    stg.BANK_CHARGE_BEARER,
    stg.REMIT_TO_SUPPLIER_NAME,
    stg.REMIT_TO_SUPPLIER_NUM,
    stg.REMIT_TO_ADDRESS_NAME,
    stg.PAYMENT_PRIORITY,
    stg.SETTLEMENT_PRIORITY,
    stg.UNIQUE_REMITTANCE_IDENTIFIER,
    stg.URI_CHECK_DIGIT,
    stg.PAYMENT_REASON_CODE,
    stg.PAYMENT_REASON_COMMENTS,
    stg.REMITTANCE_MESSAGE1,
    stg.REMITTANCE_MESSAGE2,
    stg.REMITTANCE_MESSAGE3,
    stg.AWT_GROUP_NAME,
    stg.SHIP_TO_LOCATION,
    stg.TAXATION_COUNTRY,
    stg.DOCUMENT_SUB_TYPE,
    stg.TAX_INVOICE_INTERNAL_SEQ,
    stg.SUPPLIER_TAX_INVOICE_NUMBER,
    stg.TAX_INVOICE_RECORDING_DATE,
    stg.SUPPLIER_TAX_INVOICE_DATE,
    stg.SUPPLIER_TAX_EXCHANGE_RATE,
    stg.PORT_OF_ENTRY_CODE,
    stg.CORRECTION_YEAR,
    stg.CORRECTION_PERIOD,
    stg.IMPORT_DOCUMENT_NUMBER,
    stg.IMPORT_DOCUMENT_DATE,
    stg.CONTROL_AMOUNT,
    stg.CALC_TAX_DURING_IMPORT_FLAG,
    stg.ADD_TAX_TO_INV_AMT_FLAG,
    stg.ATTRIBUTE_CATEGORY,
    stg.ATTRIBUTE1,
    stg.ATTRIBUTE2,
    stg.ATTRIBUTE3,
    stg.ATTRIBUTE4,
    stg.ATTRIBUTE5,
    stg.ATTRIBUTE6,
    stg.ATTRIBUTE7,
    stg.ATTRIBUTE8,
    stg.ATTRIBUTE9,
    stg.ATTRIBUTE10,
    stg.ATTRIBUTE11,
    stg.ATTRIBUTE12,
    stg.ATTRIBUTE13,
    stg.ATTRIBUTE14,
    stg.ATTRIBUTE15,
    stg.ATTRIBUTE_NUMBER1,
    stg.ATTRIBUTE_NUMBER2,
    stg.ATTRIBUTE_NUMBER3,
    stg.ATTRIBUTE_NUMBER4,
    stg.ATTRIBUTE_NUMBER5,
    stg.ATTRIBUTE_DATE1,
    stg.ATTRIBUTE_DATE2,
    stg.ATTRIBUTE_DATE3,
    stg.ATTRIBUTE_DATE4,
    stg.ATTRIBUTE_DATE5,
    stg.GLOBAL_ATTRIBUTE_CATEGORY,
    stg.GLOBAL_ATTRIBUTE1,
    stg.GLOBAL_ATTRIBUTE2,
    stg.GLOBAL_ATTRIBUTE3,
    stg.GLOBAL_ATTRIBUTE4,
    stg.GLOBAL_ATTRIBUTE5,
    stg.GLOBAL_ATTRIBUTE6,
    stg.GLOBAL_ATTRIBUTE7,
    stg.GLOBAL_ATTRIBUTE8,
    stg.GLOBAL_ATTRIBUTE9,
    stg.GLOBAL_ATTRIBUTE10,
    stg.GLOBAL_ATTRIBUTE11,
    stg.GLOBAL_ATTRIBUTE12,
    stg.GLOBAL_ATTRIBUTE13,
    stg.GLOBAL_ATTRIBUTE14,
    stg.GLOBAL_ATTRIBUTE15,
    stg.GLOBAL_ATTRIBUTE16,
    stg.GLOBAL_ATTRIBUTE17,
    stg.GLOBAL_ATTRIBUTE18,
    stg.GLOBAL_ATTRIBUTE19,
    stg.GLOBAL_ATTRIBUTE20,
    stg.GLOBAL_ATTRIBUTE_NUMBER1,
    stg.GLOBAL_ATTRIBUTE_NUMBER2,
    stg.GLOBAL_ATTRIBUTE_NUMBER3,
    stg.GLOBAL_ATTRIBUTE_NUMBER4,
    stg.GLOBAL_ATTRIBUTE_NUMBER5,
    stg.GLOBAL_ATTRIBUTE_DATE1,
    stg.GLOBAL_ATTRIBUTE_DATE2,
    stg.GLOBAL_ATTRIBUTE_DATE3,
    stg.GLOBAL_ATTRIBUTE_DATE4,
    stg.GLOBAL_ATTRIBUTE_DATE5,
    stg.IMAGE_DOCUMENT_URI,
    stg.EXTERNAL_BANK_ACCOUNT_NUMBER,
    stg.EXT_BANK_ACCOUNT_IBAN_NUMBER,
    stg.REQUESTER_EMAIL_ADDRESS,
    stg.INTERCOMPANY_CROSSCHARGE_FLAG,
    stg.SOURCE_ID,
    -- 5. STG_SEQUENCE_ID
    stg.STG_SEQUENCE_ID,
    -- 6. RUN_ID
    tfm.RUN_ID,
    -- 7. PREFIX (from PIPELINE_RUN)
    cm.PREFIX,
    -- 8. SCENARIO_ID
    stg.SCENARIO_ID,
    -- 9. STAGE_DATE
    stg.STAGE_DATE,
    -- 10. LAST_UPDATED_DATE
    NVL(tfm.LAST_UPDATED_DATE, stg.LAST_UPDATED_DATE)      AS LAST_UPDATED_DATE
FROM DMT_OWNER.DMT_AP_INVOICES_INT_STG_TBL stg
LEFT JOIN (
    SELECT t.*,
           ROW_NUMBER() OVER (PARTITION BY t.STG_SEQUENCE_ID
                              ORDER BY t.TFM_SEQUENCE_ID DESC) AS rn
    FROM   DMT_OWNER.DMT_AP_INVOICES_INT_TFM_TBL t
) tfm ON tfm.STG_SEQUENCE_ID = stg.STG_SEQUENCE_ID AND tfm.rn = 1
LEFT JOIN DMT_OWNER.DMT_PIPELINE_RUN_TBL cm
    ON cm.RUN_ID = tfm.RUN_ID;
